import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Navbar from './components/Navbar';
import Login from './pages/Login';
import Register from './pages/Register';
import api from './api/axiosConfig';

const Home = () => {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    api.get('/products')
      .then(res => setProducts(res.data))
      .catch(err => console.error("Error fetching products", err));
  }, []);

  return (
    <div className="py-12 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto">
      <div className="text-center mb-12">
        <h1 className="text-5xl font-extrabold text-gray-900 mb-4 tracking-tight">Welcome to SmartPoint</h1>
        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
          Discover handpicked products with unbeatable prices across Top Categories!
        </p>
      </div>

      {products.length === 0 ? (
        <p className="text-center text-gray-500">Loading products from Local Database...</p>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {products.map(p => (
            <div key={p.id} className="bg-white rounded-2xl shadow-lg hover:shadow-2xl transition-all overflow-hidden border border-gray-100 flex flex-col">
              <img src={p.imageUrl || "https://picsum.photos/400/300"} alt={p.name} className="h-48 w-full object-cover" />
              <div className="p-5 flex flex-col flex-grow">
                <div className="text-xs font-semibold text-primary mb-1 uppercase tracking-wider">{p.categoryName || 'General'}</div>
                <h3 className="text-xl font-bold text-gray-900 mb-2">{p.name}</h3>
                <p className="text-gray-600 text-sm mb-4 line-clamp-2 flex-grow">{p.description}</p>
                <div className="flex items-center justify-between mt-auto">
                  <span className="text-2xl font-extrabold text-gray-900">${p.price}</span>
                  <button className="btn-primary text-sm px-4 py-2">Add to Cart</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const Dashboard = () => (
  <div className="py-12 px-8 max-w-7xl mx-auto">
    <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100">
      <h1 className="text-4xl font-bold mb-4 text-gray-900">Dashboard</h1>
      <p className="text-lg text-gray-600">Welcome back to SmartPoint! Authentication works beautifully. You can now securely manage your orders here.</p>
    </div>
  </div>
);

function App() {
  return (
    <Router>
      <div className="font-sans min-h-screen flex flex-col bg-gray-50">
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/dashboard" element={<Dashboard />} />
          </Routes>
        </main>
        <footer className="bg-white shadow-inner py-8 mt-12">
            <p className="text-center text-gray-500 text-sm">© 2026 SmartPoint App. React + Spring Boot Presentation Ready.</p>
        </footer>
      </div>
    </Router>
  );
}

export default App;
